#!/bin/bashset -eecho "========================================"echo "  Vendor Manager - Linux Setup"echo "========================================"echo ""# Parse argumentsSKIP_SYSTEM=falseRUN_APP=falsefor arg in "$@"; do    case $arg in        --skip-system) SKIP_SYSTEM=true ;;        --run-app) RUN_APP=true ;;    esacdoneecho "[1/4] Checking for Python 3..."if ! command -v python3 &> /dev/null; then    echo "   ERROR: Python 3 not found. Please install it first."    exit 1fiPYTHON_VERSION=$(python3 --version)echo "   Found: $PYTHON_VERSION"echo ""echo "[2/4] Creating virtual environment..."python3 -m venv .venvsource .venv/bin/activateecho "   Virtual environment created and activated"echo ""echo "[3/4] Installing Python dependencies..."python -m pip install --upgrade pippip install -r requirements.txtecho "   Python dependencies installed"echo ""echo "[4/4] Checking for Tesseract OCR..."if ! command -v tesseract &> /dev/null; then    if [ "$SKIP_SYSTEM" = true ]; then        echo "   [WARN] Skipping Tesseract installation by request."        echo "   OCR feature will not work without Tesseract."    else        if command -v apt-get &> /dev/null; then            echo "   Installing Tesseract via apt-get..."            sudo apt-get update            sudo apt-get install -y tesseract-ocr libtesseract-dev        elif command -v dnf &> /dev/null; then            echo "   Installing Tesseract via dnf..."            sudo dnf install -y tesseract        elif command -v yum &> /dev/null; then            echo "   Installing Tesseract via yum..."            sudo yum install -y tesseract        elif command -v pacman &> /dev/null; then            echo "   Installing Tesseract via pacman..."            sudo pacman -S --noconfirm tesseract        elif command -v zypper &> /dev/null; then            echo "   Installing Tesseract via zypper..."            sudo zypper install -y tesseract-ocr        elif command -v apk &> /dev/null; then            echo "   Installing Tesseract via apk..."            sudo apk add tesseract-ocr        else            echo "   [WARN] Could not detect package manager."            echo "   Please install Tesseract manually for your distribution."        fi    fielse    TESS_VERSION=$(tesseract --version | head -n1)    echo "   Found: $TESS_VERSION"fiecho ""echo "========================================"echo "  Setup Complete!"echo "========================================"echo ""echo "To activate the environment and run the app:"echo "  source .venv/bin/activate"echo "  python vendor_manager.py"echo ""echo "Or run directly:"echo "  ./.venv/bin/python vendor_manager.py"echo ""if [ "$RUN_APP" = true ]; then    echo "Launching Vendor Manager..."    ./.venv/bin/python vendor_manager.pyfi